/* app.module.css */

/* Local scope (default) - gets hashed */
.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 24px;
}

/* Global scope - NOT hashed, available everywhere */
:global(.visually-hidden) {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  border: 0;
}

/* Mix local and global */
.wrapper {
  padding: 16px;
}

/* Target a global class inside a local scope */
.wrapper :global(.third-party-widget) {
  border: 1px solid #e5e7eb;
  border-radius: 8px;
}

/* Target local class inside global context */
:global(.dark-theme) .container {
  background: #1f2937;
  color: #f9fafb;
}

/* CSS custom properties are always global (not class names) */
.theme {
  --primary: #3b82f6;
  --text: #111827;
  --bg: #ffffff;
}

/* ---- File without modules (global by default) ---- */
/* global.css - imported normally, not as module */
/* import './global.css'; */
body {
  margin: 0;
  font-family: system-ui, sans-serif;
}

* {
  box-sizing: border-box;
}

/* Alert.module.css */
.alert {
  padding: 16px;
  border-radius: 8px;
  border: 1px solid;
  display: flex;
  align-items: center;
  gap: 12px;
}

.success {
  background: #f0fdf4;
  border-color: #86efac;
  color: #166534;
}

.error {
  background: #fef2f2;
  border-color: #fca5a5;
  color: #991b1b;
}

.dismissible {
  padding-right: 40px;
  position: relative;
}

.closeButton {
  position: absolute;
  top: 12px;
  right: 12px;
  background: none;
  border: none;
  cursor: pointer;
  color: inherit;
}

/* ---- Component ---- */
// Alert.jsx
import styles from './Alert.module.css';

function Alert({ type = 'success', dismissible, children, onClose }) {
  // Method 1: Template literal
  const className = `${styles.alert} ${styles[type]} ${
    dismissible ? styles.dismissible : ''
  }`.trim();

  // Method 2: Array join
  const classNames = [
    styles.alert,
    styles[type],
    dismissible && styles.dismissible,
  ].filter(Boolean).join(' ');

  // Method 3: clsx/classnames library (recommended)
  // import clsx from 'clsx';
  // const className = clsx(styles.alert, styles[type], {
  //   [styles.dismissible]: dismissible,
  // });

  return (
    <div className={classNames}>
      {children}
      {dismissible && (
        <button
          className={styles.closeButton}
          onClick={onClose}
          aria-label="Dismiss"
        >
          &times;
        </button>
      )}
    </div>
  );
}

