});

export const title = style({
  fontSize: '18px',
  fontWeight: 600,
  color: vars.color.text,
  margin: 0,
});

// Variant styles
export const buttonVariants = styleVariants({
  primary: {
    background: vars.color.primary,
    color: '#fff',
    padding: `${vars.space.sm} ${vars.space.md}`,
    border: 'none',
    borderRadius: '6px',
    cursor: 'pointer',
  },
