    color: '#374151',
    padding: `${vars.space.sm} ${vars.space.md}`,
    border: 'none',
    borderRadius: '6px',
    cursor: 'pointer',
  },
});

// ---- Component ---- //
// Card.tsx
import { card, title, buttonVariants } from './styles.css';

function Card() {
