import styled from 'styled-components';

const Container = styled.div`
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 24px;
`;

const fontSizes = { 1: '32px', 2: '24px', 3: '18px' };
const Heading = styled.h1.attrs((props) => ({
  as: `h${props.level || 1}`,
}))`
  font-size: ${(props) => fontSizes[props.level] || '32px'};
  font-weight: 700;
  color: #111827;
  margin: 0 0 16px;
`;

const variantStyles = {
  primary: { bg: '#3b82f6', color: '#fff' },
  secondary: { bg: '#e5e7eb', color: '#374151' },
  danger: { bg: '#ef4444', color: '#fff' },
};

const Button = styled.button`
  padding: 10px 20px;
  border: none;
  border-radius: 6px;
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  background: ${(props) => (variantStyles[props.variant] || variantStyles.primary).bg};
  color: ${(props) => (variantStyles[props.variant] || variantStyles.primary).color};
  &:hover {
    opacity: 0.9;
  }
`;

const Flex = styled.div`
  display: flex;
  flex-direction: ${(props) => props.direction || 'row'};
  gap: ${(props) => props.gap || '0px'};
  align-items: ${(props) => props.align || 'stretch'};
`;

function App() {
  return (
    <Container>
      <Heading level={1}>Dashboard</Heading>
      <Heading level={2}>Recent Activity</Heading>
      <Flex direction="row" gap="12px" align="center">
        <Button variant="primary">Save Changes</Button>
        <Button variant="secondary">Cancel</Button>
        <Button variant="danger">Delete Account</Button>
      </Flex>
    </Container>
  );
}

